udf.func(
  'chatWithAI',
  async (userMessage: string, previousResponseId: string): Promise<AIResponse> => {
    const endpoint = process.env.AZURE_AI_FOUNDRY_ENDPOINT;
    const deploymentName = process.env.AZURE_AI_FOUNDRY_DEPLOYMENT || 'gpt-4o';
    
    console.log('[HemyAI Function] Processing message:', userMessage.substring(0, 50) + '...');

    if (!endpoint) {
      console.error('[HemyAI Function] Configuration missing: AZURE_AI_FOUNDRY_ENDPOINT');
      return {
        output_text: '❌ **Configuration Error**: Azure AI Foundry endpoint not configured on server',
      };
    }

    try {
      console.log('[HemyAI Function] Using endpoint:', endpoint);
      console.log('[HemyAI Function] Using deployment:', deploymentName);

      // Set up Azure authentication with DefaultAzureCredential
      // This uses the environment's default credential chain:
      // 1. Environment variables (AZURE_TENANT_ID, AZURE_CLIENT_ID, AZURE_CLIENT_SECRET)
      // 2. Managed Identity (if running on Azure)
      // 3. Azure CLI credentials
      // 4. Visual Studio Code credentials
      // See: https://learn.microsoft.com/en-us/javascript/api/@azure/identity
      
      const credential = new DefaultAzureCredential();
      const scope = 'https://ai.azure.com/.default';
      
      const tokenProvider = getBearerTokenProvider(credential, scope);

      // Create OpenAI client targeting Azure AI Foundry
      const client = new OpenAI({
        baseURL: endpoint,
        apiKey: '', // Will be set via tokenProvider
        defaultHeaders: {
          'api-version': '2024-08-01-preview', // Azure AI Foundry API version
        },
        dangerouslyAllowBrowser: false, // This is server-side, so false is correct
      });

      // Call Azure Responses API with proper protocol
      // The OpenAI client automatically uses the token provider for auth
      console.log('[HemyAI Function] Calling Azure Responses API...');
      
      const response = await client.responses.create({
        model: deploymentName,
        input: userMessage,
        ...(previousResponseId && previousResponseId.trim() !== '' && { previous_response_id: previousResponseId }), // Only include if non-empty
        max_tokens: 1024,
        temperature: 0.7,
      });

      console.log('[HemyAI Function] Response received:', response.id);

      // Parse Azure Responses API response
      const outputText = 
        Array.isArray(response.output) && response.output.length > 0
          ? response.output[0]
          : typeof response.output === 'string'
          ? response.output
          : 'No response from AI';

      return {
        id: response.id,
        output_text: outputText,
        // If API returns structured data, parse it here
        table: (response as any).table,
        chart: (response as any).chart,
      };
    } catch (error) {
      console.error('[HemyAI Function] Request failed:', error);
      
      const errorMessage = error instanceof Error ? error.message : 'Connection failed';
      console.error('[HemyAI Function] Error details:', errorMessage);

      // Log full error for debugging (server-side only)
      if (error instanceof Error && error.stack) {
        console.error('[HemyAI Function] Stack:', error.stack);
      }

      return {
        output_text: `❌ **Error**: ${errorMessage}\n\nCheck server logs for details.`,
      };
    }
  },
  ['userMessage', 'previousResponseId'] // Input parameters for type safety
)
